      },
    ],
    [t],
  )

  const yearStr = useMemo(
    () => ({
      Q1: t('kpis:year.Q1'),
      Q2: t('kpis:year.Q2'),
      Q3: t('kpis:year.Q3'),
      Q4: t('kpis:year.Q4'),
      H1: t('kpis:year.Q2'),
      H2: t('kpis:year.Q4'),
      ANNUAL: t('kpis:year.Q4'),
    }),
    [t],
  )

  useEffect(() => {
    setFormType(type)
  }, [])

  const targetSuffix = useMemo(() => {
    const suffixObj: Record<string, string> = {
      '0': '%',
      '1': 'AED',
      '2': '',
      '3': isLanguageAR ? 'ساعة' : 'hour',
      '4': isLanguageAR ? 'اليوم' : 'days',
    }
    return suffixObj[String(measurementUnit ?? '')] ?? ''
  }, [measurementUnit, isLanguageAR])

  const generateTableData = (
    keys: string[],
    endDate: any,
    isYear = false,
    isMonth = false,
  ) =>
    keys.map((key) => ({
      key,
      measurementName: `${isYear ? t('kpis:year.Q4') : isMonth ? MONTH_ENUM[key] : yearStr[key]} ${dayjs(endDate).year()}`,
      targetPerformance: '',
      actualPerformance: null,
      periodPerformanceRatio: '',
      status: null as null,
      attachments: '--',
    }))

  const safeSetTableData = (nextData: any[]) => {
    setTableData((prev) => (_.isEqual(prev, nextData) ? prev : nextData))
  }

  // 记录上一次写入 measurementTable 的数据快照，避免数据未变化时重复调用导致无限循环
  const prevMeasurementTableJsonRef = useRef<string>('')
  const safeSetMeasurementTable = (nextData: any[]) => {
    const nextJson = JSON.stringify(nextData)
    if (prevMeasurementTableJsonRef.current !== nextJson) {
      prevMeasurementTableJsonRef.current = nextJson
      setMeasurementTable(nextData)
    }
  }

  // 用 ref 实时跟踪 measurementTable 最新值，避免 effect closure 中拿到过期快照
  const measurementTableRef = useRef<any[]>(measurementTable ?? [])
  useEffect(() => {
    measurementTableRef.current = measurementTable ?? []
  }, [measurementTable])

  // 按”周期+起止日期”缓存各周期的表格数据，切换回原周期时可恢复
  const cachedTableDataRef = useRef<Record<string, any[]>>({})
  const prevCycleKeyRef = useRef<string>('')

  // 根据”统计周期 + 起止日期”动态生成表格行数据。
  // 这个 effect 的作用是：当用户修改周期或日期时，立即重算每一行频次（年/半年/季度/月）。
  useEffect(() => {
    const currentKey = `${formMeasCycle}-${formStartDate}-${formEndDate}`

    // 前置条件不完整时，清空表格，避免展示过期数据。
    if (
      formMeasCycle === undefined ||
      formMeasCycle === null ||
      !formStartDate ||
      !formEndDate
    ) {
      if (prevCycleKeyRef.current) {
        cachedTableDataRef.current[prevCycleKeyRef.current] =
          measurementTableRef.current
        prevCycleKeyRef.current = ''
      }
      safeSetTableData([])
      return
    }

    // 切走前把当前数据存入缓存
    if (prevCycleKeyRef.current && prevCycleKeyRef.current !== currentKey) {
      cachedTableDataRef.current[prevCycleKeyRef.current] =
        measurementTableRef.current
    }
    // 仅组件挂载时（prevKey 为空），若 measurementTable 已有数据（如编辑回填），先缓存起来
    // 切换周期时不走这里，避免把旧周期数据错误缓存到新 key 下
    if (
      !prevCycleKeyRef.current &&
      !cachedTableDataRef.current[currentKey] &&
      measurementTableRef.current?.length > 0
    ) {
      cachedTableDataRef.current[currentKey] = measurementTableRef.current
    }
    prevCycleKeyRef.current = currentKey

    // 有缓存则直接恢复，不重新生成空白数据
    if (cachedTableDataRef.current[currentKey]?.length > 0) {
      const cached = cachedTableDataRef.current[currentKey]
      safeSetTableData(cached)
      safeSetMeasurementTable(cached)
      return
    }

    try {
      // keys 表示每一行对应的周期标识（如 ANNUAL / H1 / Q2 / jan 等）。
      let keys: string[]
      let isYear = false
      let isMonth = false
      const end = formEndDate
      // 按不同统计周期，生成对应的 keys 列表。
      if (formMeasCycle === measurementCycleEnum.Annual) {
        keys = [yearCode]
        isYear = true
      } else if (formMeasCycle === measurementCycleEnum.Semiannual) {
        keys = calculateHalfYears(formStartDate, formEndDate).map((item) =>
          yearQuarterSwitch(formMeasCycle, item),
