import { useCallback, useContext, useEffect, useRef, useState } from 'react'
import { EditableContext } from '../../EditableTable'
import {
  DatePicker,
  Form,
  Input,
  InputNumber,
  Select,
} from '@arco-design/web-react'
import './style/style.less'
import EditTableCellFileUpload from '@/pages/StrategyCycle/components/EditableTable/components/EditTableCellFileUpload/EditTableCellFileUpload.tsx'
import { MaxLengthEnum } from '@common/constants/maxLength.ts'
import { useTranslation } from 'react-i18next'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { isReadServerTextData } from '@common/constants/env'
import _ from 'lodash'

const FormItem = Form.Item

//colum type:select/date/input
export enum ColumType {
  'SELECT' = 'select',
  'DATE' = 'date',
  'INPUT' = 'input',
  'NUMBER' = 'number',
  'FILESUPDATE' = 'filesUpdate',
}

function EditableCell(props) {
  const {
    children,
    className,
    rowData,
    column,
    onHandleSave,
    onStatus,
    onHandleLoading,
    clearDoneKey,
  } = props
  const milestoneFirstActivityKey = column['key']
  //上传文件框的status
  const ref = useRef(null)
  const { getForm } = useContext(EditableContext)
  const [editing, setEditing] = useState(false)
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['milestones'])
  //当数据发生变化时更新表单值
  useEffect(() => {
    const form = getForm()
    form.setFieldsValue({
      [`${column.dataIndex}-${rowData.key}`]: rowData[column.dataIndex],
    })
  }, [rowData[column.dataIndex], column.dataIndex, rowData.key])

  const handleClick = useCallback(
    (e) => {
      if (
        editing &&
        column.editable &&
        ref.current &&
        !ref.current.contains(e.target) &&
        !e.target.classList.contains('js-demo-select-option')
      ) {
        cellValueChangeHandler(rowData[column.dataIndex])
      }
    },
    [editing, rowData, column],
  )
  useEffect(() => {
    document.addEventListener('click', handleClick, true)
    return () => {
      document.removeEventListener('click', handleClick, true)
    }
  }, [handleClick])
  useEffect(() => {
    validateForm()
  }, [column, rowData])

  const validateForm = () => {
    const form = getForm()
    form.validate([column.dataIndex], (errors, values) => {
      if (!errors || !errors[column.dataIndex]) {
        onStatus &&
          onStatus({
            rowKey: rowData.key,
            columnKey: column.dataIndex,
            status: true,
          })
      } else {
        onStatus &&
          onStatus({
            rowKey: rowData.key,
            columnKey: column.dataIndex,
            status: false,
            error: errors[column.dataIndex],
          })
      }
    })
  }

  const cellValueChangeHandler = (value) => {
    const values = {
      [column.dataIndex]: value,
    }
    onHandleSave && onHandleSave({ ...rowData, ...values })
  }
  const generateFormItemByType = (type, editable) => {
    if (editable) {
      const form = getForm()
      if (type === ColumType.SELECT) {
        return (
          <FormItem
            style={{ marginBottom: 0 }}
            labelCol={{ span: 0 }}
            wrapperCol={{ span: 24 }}
            // initialValue={rowData[column.dataIndex]}
            field={`${column.dataIndex}-${rowData.key}`}
            rules={column.rules}
            noStyle
            validateTrigger={[]}
          >
            <Select
              onSelect={cellValueChangeHandler}
              options={column.selectOptions}
              disabled={
                typeof column?.disabled === 'function'
                  ? column?.disabled(rowData) // 函数类型：传入rowData，得到布尔值
                  : column?.disabled // 静态类型：直接使用布尔值
              }
              style={{ width: `clac(${column?.width} - 32px)` }}
            />
          </FormItem>
        )
      }
      if (type === ColumType.DATE) {
        return (
          <FormItem
            style={{ marginBottom: 0 }}
            labelCol={{ span: 0 }}
            wrapperCol={{ span: 24 }}
            // initialValue={rowData[column.dataIndex]}
            field={`${column.dataIndex}-${rowData.key}`}
            rules={column.rules}
            noStyle
            validateTrigger={[]}
          >
            <DatePicker
              disabled={
                typeof column?.disabled === 'function'
                  ? column?.disabled(rowData) // 函数类型：传入rowData，得到布尔值
                  : column?.disabled // 静态类型：直接使用布尔值
              }
              onChange={cellValueChangeHandler}
            />
          </FormItem>
        )
      }
      //input类型
      if (type === ColumType.INPUT) {
        return (
          <FormItem
            style={{ marginBottom: 0 }}
            labelCol={{ span: 0 }}
            wrapperCol={{ span: 24 }}
            // initialValue={rowData[column.dataIndex]}
            field={`${column.dataIndex}-${rowData.key}`}
            rules={column.rules}
            noStyle
            validateTrigger={[]}
          >
            <Input
              // ref={refInput}
              onChange={cellValueChangeHandler}
              placeholder={column?.placeholder}
              suffix={column.suffix}
              disabled={
                typeof column?.disabled === 'function'
                  ? column?.disabled(rowData) // 函数类型：传入rowData，得到布尔值
                  : column?.disabled // 静态类型：直接使用布尔值
              }
            />
          </FormItem>
        )
      }
      //文件上传框
      if (type === ColumType.FILESUPDATE) {
        const targetIsZero = rowData[column.target] == 0
        return (
          <FormItem
            style={{ marginBottom: 0 }}
            labelCol={{ span: 0 }}
            wrapperCol={{ span: 24 }}
            // initialValue={rowData[column.dataIndex]}
            field={`${column.dataIndex}-${rowData.key}`}
            //column?.isOnlyFirst 判断是否 只首行校验
            //milestoneFirstActivityKey === rowData.key  判断是否是当前行
            //targetIsZero 判断 rowData[column.target]== 0 的时候 不进行必填校验 。
            rules={
              column?.isOnlyFirst
                ? milestoneFirstActivityKey === rowData.key
                  ? targetIsZero
                    ? ''
                    : column.rules
                  : ''
                : column.rules
            }
            noStyle
            validateTrigger={[]}
          >
            <EditTableCellFileUpload
              canUpload={editable}
              field={`${column.dataIndex}-${rowData.key}`}
              fileType={column?.fileType ?? 0}
              onUpload={cellValueChangeHandler}
              disabled={
                typeof column?.disabled === 'function'
                  ? column?.disabled(rowData) // 函数类型：传入rowData，得到布尔值
                  : column?.disabled // 静态类型：直接使用布尔值
              }
              getUploadLoading={(c) => {
                onHandleLoading && onHandleLoading(c, rowData.key)
              }}
              clearDoneKey={(c) => {
                clearDoneKey && clearDoneKey(rowData.key)
              }}
              defaultFileList={rowData[column.dataIndex]}
              formInstance={getForm()}
              readOnly={column?.readOnly}
              // onChange={cellValueChangeHandler}
            />
          </FormItem>
        )
      }

      //数字输入框
      if (type === ColumType.NUMBER) {
        return (
          <div className='editable-inputNumber'>
            <FormItem
              style={{ marginBottom: 0 }}
              labelCol={{ span: 0 }}
              wrapperCol={{ span: 24 }}
              initialValue={rowData[column.dataIndex]}
              field={`${column.dataIndex}-${rowData.key}`}
              rules={column.rules}
              noStyle
              validateTrigger={[]}
            >
              <InputNumber
                // ref={refInput}
                suffix={column?.suffix}
                disabled={
                  typeof column?.disabled === 'function'
                    ? column?.disabled(rowData) // 函数类型：传入rowData，得到布尔值
                    : column?.disabled // 静态类型：直接使用布尔值
                }
                max={column?.max}
                min={column?.min}
                maxLength={MaxLengthEnum.TemporaryLength}
                precision={2}
                onChange={cellValueChangeHandler}
                placeholder={column?.placeholder}
                value={rowData[column.dataIndex]}
              />
            </FormItem>
            {!_.isEmpty(column.target) && (
              <div className='editable-inputNumber-suffix'>
                {/* {Number(
                  (rowData[column.target] * rowData[column.dataIndex]) / 100 ||
                    0,
                ).toFixed(2) + '%'}
                &nbsp; */}
                {t('milestones:of', { target: rowData[column.target] })}
              </div>
            )}
          </div>
        )
      }
    } else {
      return children
    }
  }

  return (
    <div ref={ref}>{generateFormItemByType(column.type, column.editable)}</div>
  )
}

export default EditableCell

  }
}

